package com.example.auth.mfa;

import com.example.auth.user.User;
import com.example.auth.user.UserRepository;
import com.example.auth.mfa.dto.BackupCodesResponse;
import com.example.auth.mfa.dto.EnableMfaRequest;
import jakarta.transaction.Transactional;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {
    private static final int DEFAULT_CODE_COUNT = 10;
    private static final int CODE_LENGTH = 10;
    private static final String ALPHABET = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             UserRepository userRepository,
                             PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public BackupCodesResponse enableMfaAndGenerateBackupCodes(EnableMfaRequest request) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        user.setMfaSecret(request.getSecret());

        backupCodeRepository.deleteAll(backupCodeRepository.findByUserAndUsedFalse(user));

        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < DEFAULT_CODE_COUNT; i++) {
            String code = generateCode();
            plainCodes.add(formatCode(code));

            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(passwordEncoder.encode(normalize(code)));
            backupCode.setUsed(false);
            backupCodeRepository.save(backupCode);
        }

        userRepository.save(user);
        return new BackupCodesResponse(plainCodes);
    }

    @Transactional
    public BackupCodesResponse regenerateBackupCodes(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        List<BackupCode> existing = backupCodeRepository.findByUserAndUsedFalse(user);
        backupCodeRepository.deleteAll(existing);

        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < DEFAULT_CODE_COUNT; i++) {
            String code = generateCode();
            plainCodes.add(formatCode(code));

            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(passwordEncoder.encode(normalize(code)));
            backupCodeRepository.save(backupCode);
        }

        return new BackupCodesResponse(plainCodes);
    }

    @Transactional
    public boolean consumeBackupCode(User user, String rawCode) {
        if (rawCode == null || rawCode.isBlank()) {
            return false;
        }

        String normalized = normalize(rawCode);
        List<BackupCode> activeCodes = backupCodeRepository.findByUserAndUsedFalse(user);

        for (BackupCode backupCode : activeCodes) {
            if (passwordEncoder.matches(normalized, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCodeRepository.save(backupCode);
                return true;
            }
        }

        return false;
    }

    public long countRemainingCodes(User user) {
        return backupCodeRepository.countByUserAndUsedFalse(user);
    }

    private String generateCode() {
        StringBuilder sb = new StringBuilder(CODE_LENGTH);
        for (int i = 0; i < CODE_LENGTH; i++) {
            sb.append(ALPHABET.charAt(secureRandom.nextInt(ALPHABET.length())));
        }
        return sb.toString();
    }

    private String formatCode(String code) {
        String normalized = normalize(code);
        return normalized.substring(0, 5) + "-" + normalized.substring(5);
    }

    private String normalize(String code) {
        return code.replace("-", "").replace(" ", "").trim().toUpperCase();
    }
}

package com.example.auth.auth;

import com.example.auth.auth.dto.LoginRequest;
import com.example.auth.auth.dto.LoginResponse;
import com.example.auth.mfa.BackupCodeService;
import com.example.auth.user.User;
import com.example.auth.user.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
public class AuthenticationService {
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final BackupCodeService backupCodeService;

    public AuthenticationService(UserRepository userRepository,
                                 PasswordEncoder passwordEncoder,
                                 BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.backupCodeService = backupCodeService;
    }

    public LoginResponse authenticate(LoginRequest request) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));

        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
            throw new IllegalArgumentException("Invalid credentials");
        }

        if (!user.isMfaEnabled()) {
            return new LoginResponse(true, "Authenticated", false, 0);
        }

        if (request.getBackupCode() != null && !request.getBackupCode().isBlank()) {
            boolean consumed = backupCodeService.consumeBackupCode(user, request.getBackupCode());
            if (consumed) {
                long remaining = backupCodeService.countRemainingCodes(user);
                return new LoginResponse(true, "Authenticated using backup code", false, remaining);
            }
        }

        if (request.getTotpCode() != null && !request.getTotpCode().isBlank()) {
            if (TotpService.verifyCode(user.getMfaSecret(), request.getTotpCode())) {
                long remaining = backupCodeService.countRemainingCodes(user);
                return new LoginResponse(true, "Authenticated using TOTP", false, remaining);
            }
        }

        return new LoginResponse(false, "MFA required: provide valid TOTP or backup code", true,
                backupCodeService.countRemainingCodes(user));
    }
}

package com.example.auth.auth;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.time.Instant;
import java.util.Base64;

public final class TotpService {
    private TotpService() {
    }

    public static boolean verifyCode(String base64Secret, String code) {
        if (base64Secret == null || base64Secret.isBlank() || code == null || !code.matches("\\d{6}")) {
            return false;
        }

        long timeWindow = Instant.now().getEpochSecond() / 30;
        for (long i = -1; i <= 1; i++) {
            String generated = generateCode(base64Secret, timeWindow + i);
            if (code.equals(generated)) {
                return true;
            }
        }
        return false;
    }

    private static String generateCode(String base64Secret, long counter) {
        try {
            byte[] key = Base64.getDecoder().decode(base64Secret);
            byte[] data = ByteBuffer.allocate(8).putLong(counter).array();

            Mac mac = Mac.getInstance("HmacSHA1");
            mac.init(new SecretKeySpec(key, "HmacSHA1"));
            byte[] hash = mac.doFinal(data);

            int offset = hash[hash.length - 1] & 0xF;
            int binary = ((hash[offset] & 0x7F) << 24)
                    | ((hash[offset + 1] & 0xFF) << 16)
                    | ((hash[offset + 2] & 0xFF) << 8)
                    | (hash[offset + 3] & 0xFF);

            int otp = binary % 1_000_000;
            return String.format("%06d", otp);
        } catch (Exception e) {
            return "";
        }
    }
}

